function parseRange(s) {
  if (s.includes('-')) {
    const [a, b] = s.split('-').map(Number);
    if (a <= b) {
      const result = [];
      for (let i = a; i <= b; i++) result.push(i);
      return result;
    } else {
      const result = [];
      for (let i = a; i >= b; i--) result.push(i);
      return result;
    }
  }
  return [Number(s)];
}
